// Helpers (صغيرة ومكررة هنا لاستقلال النود)
const CONFIG = { MAX_EVENTS_PER_MESSAGE: 10 };
function g(b,p,f=''){ if(!b||!p) return f; if(p.includes('[')) return b[p] ?? f;
  try{ return p.split('.').reduce((o,k)=>(o&&k in o)?o[k]:undefined,b) ?? f; }catch{ return f; } }
function extractFlatValue(o,...keys){ for(const k of keys){ const v=g(o,k);
  if(v!==undefined&&v!==null&&v!==''){ if(typeof v==='string'){ const s=v.trim();
    if(s && !s.includes('infodvnlog') && !s.includes('.com')) return s; } else return v; } } return ''; }
function classifyEvent(body){ const ks=Object.keys(body||{}); const has=p=>ks.some(k=>k.startsWith(p));
  const T=[ ['message[add]',10,'message',9], ['unsorted[add]',8,'lead_creation',6], ['talk[add]',6,'conversation',4],
            ['talk[update]',5,'conversation',4], ['leads[update]',4,'lead_management',3], ['leads[delete]',1,'deletion',1],
            ['contacts[update]',3,'contact_management',2], ['contacts[add]',2,'contact_management',2] ];
  for(const [c,p,cat,puls] of T) if(has(c)) return {event_type:c,priority:p,category:cat,expected_pulses:Math.min(puls,CONFIG.MAX_EVENTS_PER_MESSAGE)};
  return {event_type:'unknown',priority:0,category:'other',expected_pulses:1}; }
function detectPlatform(origin='', body={}){ const s=String(origin).toLowerCase();
  if(s.includes('waba')||s.includes('whatsapp')) return 'whatsapp';
  if(s.includes('instagram')||s.includes('ig')) return 'instagram';
  if(s.includes('facebook')||s.includes('fb')) return 'facebook';
  const raw=JSON.stringify(body).toLowerCase();
  if(raw.includes('whatsapp')) return 'whatsapp';
  if(raw.includes('instagram')) return 'instagram';
  if(raw.includes('facebook')) return 'facebook';
  return 'unknown'; }

return items.map(item=>{
  const raw = item.json.raw;
  const event = classifyEvent(raw);
  const lead_id = extractFlatValue(raw,'leads[update][0][id]','leads[add][0][id]','unsorted[add][0][lead_id]','talk[update][0][lead_id]');
  const entity_id = lead_id || extractFlatValue(raw,'message[add][0][entity_id]','message[add][0][element_id]','talk[update][0][entity_id]',
                                                'talk[add][0][entity_id]','unsorted[add][0][source_data][contact_id]','unsorted[add][0][source_data][from_id]');
