// Helpers
function g(b,p,f=''){ if(!b||!p) return f; if(p.includes('[')) return b[p] ?? f;
  try{ return p.split('.').reduce((o,k)=>(o&&k in o)?o[k]:undefined,b) ?? f; }catch{ return f; } }
function extractFlatValue(o,...keys){ for(const k of keys){ const v=g(o,k);
  if(v!==undefined&&v!==null&&v!==''){ if(typeof v==='string'){ const s=v.trim();
    if(s && !s.includes('infodvnlog') && !s.includes('.com')) return s; } else return v; } } return ''; }
function extractTags(body){ const tags=new Set();
  const paths=['leads[update][0][tags]','leads[add][0][tags]','unsorted[add][0][tags]','contacts[update][0][tags]',
               'leads[update][0][_embedded][tags]','talk[update][0][tags]','talk[add][0][tags]'];
  for(const p of paths){ const v=g(body,p); if(!v) continue;
    if(typeof v==='string') v.split(',').map(t=>t.trim().toLowerCase()).forEach(t=>t&&tags.add(t));
    else if(Array.isArray(v)) v.forEach(x=> typeof x==='string'? tags.add(x.toLowerCase()): (x?.name && tags.add(String(x.name).toLowerCase()))); }
  Object.keys(body).forEach(k=>{ if(k.includes('[tags][')||k.includes('[tag][')){ const v=body[k]; if(typeof v==='string') tags.add(v.toLowerCase()); }});
  return Array.from(tags); }
function extractPipelineStageInfo(body){
  const info={pipeline_id:'',pipeline_name:'',stage_id:'',stage_name:'',previous_stage_id:'',stage_changed:false};
  info.pipeline_id=extractFlatValue(body,'leads[update][0][pipeline_id]','leads[add][0][pipeline_id]','unsorted[add][0][pipeline_id]','leads[status][0][pipeline_id]','talk[update][0][pipeline_id]','leads[update][0][_embedded][pipeline_id]');
  info.stage_id=extractFlatValue(body,'leads[update][0][status_id]','leads[add][0][status_id]','unsorted[add][0][status_id]','leads[status][0][status_id]','leads[update][0][new_status_id]','talk[update][0][status_id]');
  info.previous_stage_id=extractFlatValue(body,'leads[update][0][old_status_id]','leads[status][0][old_status_id]','leads[update][0][previous_status_id]');
  info.pipeline_name=extractFlatValue(body,'leads[update][0][pipeline][name]','leads[update][0][pipeline_name]','leads[update][0][_embedded][pipeline][name]');
  info.stage_name=extractFlatValue(body,'leads[update][0][status][name]','leads[update][0][status_name]','leads[update][0][_embedded][status][name]');
  if(info.previous_stage_id && info.stage_id && info.previous_stage_id!==info.stage_id) info.stage_changed=true;
  return info; }
function extractMessageText(body,eventType){
  let text=''; const paths=[
    'talk[update][0][last_message_text]','talk[update][0][messages][0][text]','talk[update][0][last_message][text]','talk[update][0][text]','talk[add][0][text]',
    'message[add][0][text]','message[add][0][message]','message[add][0][body]','message[add][0][content]',
    'unsorted[add][0][source_data][data][0][text]','unsorted[add][0][text]',
    'leads[update][0][last_message]','leads[update][0][notes][0][text]','leads[update][0][custom_fields_values][0][values][0][value]',
    'contacts[update][0][last_message]','contacts[add][0][note]'
  ];
  for(const p of paths){ const v=g(body,p); if(typeof v==='string' && v.trim() && !v.includes('http') && !v.includes('infodvnlog') && !v.includes('.com')){ text=v.trim(); break; } }
  if(!text){
    // sweep notes/messages
    for(let i=0;i<20 && !text;i++){
      for(const p of [
        `leads[update][0][notes][${i}][text]`,
        `talk[update][0][messages][${i}][text]`,
        `talk[update][0][messages][${i}][content]`
      ]){ const v=g(body,p); if(typeof v==='string' && v.trim()){ text=v.trim(); break; } }
    }
  }
  if(!text){
    // deep JSON
    const search=(o,d=0)=>{ if(d>7||!o||typeof o!=='object') return '';
      for(const [k,v] of Object.entries(o)){
        const kk=String(k).toLowerCase();
        if(['text','message','body','content','note','last_message','last_message_text','value'].includes(kk) && typeof v==='string' && v.trim() && !v.includes('http') && !v.includes('infodvnlog') && !v.includes('.com')) return v.trim();
        if(typeof v==='object'){ const n=search(v,d+1); if(n) return n; }
      } return ''; };
    text = search(body);
  }
  return text;
}

return items.map(item=>{
  const { raw, event, ids, source, timestamps } = item.json;
  const text = extractMessageText(raw, event.event_type);
  const tags = extractTags(raw);
  const pipe = extractPipelineStageInfo(raw);
  const client_name = extractFlatValue(raw,'message[add][0][author][name]','unsorted[add][0][source_data][client][name]','unsorted[add][0][source_data][from]','unsorted[add][0][source_data][name]','contacts[add][0][name]','contacts[update][0][name]','leads[update][0][contact_name]','talk[update][0][contact_name]');
  return { json: { raw, event, ids, source, timestamps, content:{ text }, tags, pipeline: pipe, client:{ name: client_name } } };
});

const CONFIG = { TIME_WINDOW:5, MESSAGE_CACHE_TTL:120000, MAX_EVENTS_PER_MESSAGE:10, MAX_CACHE_SIZE:5000 };
function generateFingerprint({ entity_id, conversation_id, lead_id, chat_id, platform, created_at }){
  const t = created_at ? Number(created_at) : Date.now()/1000;
  const w = Math.floor(t / CONFIG.TIME_WINDOW);
  if(lead_id) return `${platform}_lead_${lead_id}_${w}`;
  if(entity_id && conversation_id) return `${platform}_${entity_id}_${conversation_id}_${w}`;
  if(chat_id) return `${platform}_chat_${chat_id}_${w}`;
  if(entity_id) return `${platform}_${entity_id}_${w}`;
  if(conversation_id) return `${platform}_${conversation_id}_${w}`;
  return `${platform}_unknown_${w}`;
}
const sd = $getWorkflowStaticData('global');
if(!sd.messageCache) sd.messageCache = {};
if(!sd.processedGroups) sd.processedGroups = {};
if(!sd.lastCleanup) sd.lastCleanup = Date.now();

function cleanup(){
  const now=Date.now(); if(now - sd.lastCleanup <= 60000) return;
  for(const k in sd.messageCache) if(now - sd.messageCache[k].timestamp > CONFIG.MESSAGE_CACHE_TTL) delete sd.messageCache[k];
  for(const k in sd.processedGroups) if(now - sd.processedGroups[k] > CONFIG.MESSAGE_CACHE_TTL) delete sd.processedGroups[k];
  const size = Object.keys(sd.messageCache).length;
  if(size > CONFIG.MAX_CACHE_SIZE){
    const arr = Object.entries(sd.messageCache).sort((a,b)=>a[1].timestamp - b[1].timestamp);
    arr.slice(0, size - CONFIG.MAX_CACHE_SIZE).forEach(([k])=> delete sd.messageCache[k]);
  }
  sd.lastCleanup = now;
}
cleanup();

return items.map(it=>{
  const { event, ids, source, timestamps, content, tags, pipeline, client } = it.json;
  const fp = generateFingerprint({ entity_id: ids.entity_id, conversation_id: ids.conversation_id, lead_id: ids.lead_id, chat_id: ids.conversation_id, platform: source.platform, created_at: timestamps.created_at });
  const now = Date.now();
  const prev = sd.messageCache[fp];
  const g = prev || {
    fingerprint: fp, entity_id:'', lead_id:'', conversation_id:'', message_id:'', talk_id:'',
    message_texts:[], client_name:'', pipeline_id:'', pipeline_name:'', stage_id:'', stage_name:'', previous_stage_id:'', stage_changed:false,
    tags:new Set(), source: source.origin || 'waba', platform: source.platform,
    pulses_received:0, expected_pulses: event.expected_pulses, has_message:false, is_new_lead:false, is_complete:false,
    created_at: timestamps.created_at, first_pulse_time: now, last_pulse_time: now,
    unique_events:new Set(), event_priorities:[], all_event_types:[]
  };
  g.pulses_received++; g.last_pulse_time = now;
  g.unique_events.add(event.event_type); g.event_priorities.push(event.priority); g.all_event_types.push(event.event_type);
  if(ids.lead_id && !g.lead_id) g.lead_id = ids.lead_id;
  if(ids.entity_id && !g.entity_id) g.entity_id = ids.entity_id;
  if(ids.conversation_id && !g.conversation_id) g.conversation_id = ids.conversation_id;
  if(ids.message_id && !g.message_id) g.message_id = ids.message_id;
  if(ids.talk_id && !g.talk_id) g.talk_id = ids.talk_id;
  if(content?.text){ g.message_texts.push({ text: content.text, event_type: event.event_type, priority: event.priority, timestamp: timestamps.created_at }); g.has_message = true; }
  if(client?.name && !g.client_name) g.client_name = client.name;
  if(pipeline?.pipeline_id){ g.pipeline_id = pipeline.pipeline_id; g.pipeline_name = pipeline.pipeline_name; }
  if(pipeline?.stage_id){ g.stage_id = pipeline.stage_id; g.stage_name = pipeline.stage_name; }
  if(pipeline?.previous_stage_id){ g.previous_stage_id = pipeline.previous_stage_id; g.stage_changed = pipeline.stage_changed; }
  (tags||[]).forEach(t=> g.tags.add(t));
  if(event.event_type==='message[add]' && content?.text) g.has_message = true;
  if(event.event_type==='unsorted[add]') g.is_new_lead = true;
  const elapsed = now - g.first_pulse_time;
  if(g.pulses_received>=g.expected_pulses || g.pulses_received>=CONFIG.MAX_EVENTS_PER_MESSAGE || elapsed > CONFIG.TIME_WINDOW*1000) g.is_complete = true;
  sd.messageCache[fp] = { ...g, unique_events_array: Array.from(g.unique_events), timestamp: now };
  return { json: { group_key: fp, is_complete: g.is_complete, expected_pulses: g.expected_pulses, pulses_received: g.pulses_received } };
});

