const PIPELINE_CONFIG = {
  '10794139': { name:'Sales Pipeline', service:'sales', critical_stages:['10794144'], ai_stages:['10794142','10794143'], bot_stages:['10794140','10794141'] },
  '10794150': { name:'Support Pipeline', service:'support', critical_stages:['10794154'], ai_stages:['10794152','10794153'], bot_stages:['10794151'] },
  '10794160': { name:'Onboarding Pipeline', service:'onboarding', critical_stages:[], ai_stages:['10794162'], bot_stages:['10794161','10794163'] },
};
const TAG_RULES = {
  ai_required:['vip','urgent','complex','ai-assist','premium','enterprise','priority'],
  bot_only:['simple','faq','auto-reply','bot-handled','no-ai','standard','routine'],
  human_required:['complaint','escalation','legal','refund','critical','emergency','manual'],
  language:{ ar:'arabic', en:'english', es:'spanish', fr:'french' }
};
function determineInterventionType(pipeline_id, stage_id, tags){
  const r={ type:'bot', reason:[], priority:'normal', service:'general', language:'ar', requires_human:false, use_ai_agent:false, confidence:'high' };
  const pc = PIPELINE_CONFIG[pipeline_id];
  if(pc){ r.service=pc.service;
    if(pc.critical_stages?.includes(stage_id)){ Object.assign(r,{type:'human',requires_human:true,priority:'critical'}); r.reason.push('critical_stage'); }
    else if(pc.ai_stages?.includes(stage_id)){ Object.assign(r,{type:'ai_agent',use_ai_agent:true,priority:'high'}); r.reason.push('ai_stage'); }
    else if(pc.bot_stages?.includes(stage_id)){ r.type='bot'; r.reason.push('bot_stage'); }
  } else { r.confidence='medium'; r.reason.push('unknown_pipeline'); }
  const human = (tags||[]).filter(t=>TAG_RULES.human_required.includes(t));
  if(human.length){ Object.assign(r,{type:'human',requires_human:true,priority:'critical'}); r.reason.push(`human_tags: ${human.join(', ')}`); }
  const ai = (tags||[]).filter(t=>TAG_RULES.ai_required.includes(t));
  if(ai.length && !r.requires_human){ Object.assign(r,{type:'ai_agent',use_ai_agent:true,priority:r.priority==='critical'?'critical':'high'}); r.reason.push(`ai_tags: ${ai.join(', ')}`); }
  const bot = (tags||[]).filter(t=>TAG_RULES.bot_only.includes(t));
  if(bot.length && !r.requires_human && !r.use_ai_agent){ Object.assign(r,{type:'bot',use_ai_agent:false,priority:'normal'}); r.reason.push(`bot_tags: ${bot.join(', ')}`); }
  for(const t of (tags||[])) if(TAG_RULES.language[t]){ r.language=t; break; }
  return r;
}
function pickFinalText(arr=[]){ if(!arr.length) return '';
  const s=[...arr].sort((a,b)=> b.priority-a.priority || b.timestamp-a.timestamp);
  const top=s[0].priority; const same=s.filter(x=>x.priority===top);
  return same.reduce((L,c)=> c.text && c.text.length>(L?.length||0)?c.text:L,'') || s[0].text || ''; }

const sd = $getWorkflowStaticData('global');

return items.map(it=>{
  const k = it.json.group_key;
  const g = sd.messageCache?.[k];
  if(!g) return { json: { error:'group_not_found', group_key:k } };

  // cross-ref بسيط: دمج معلومات ناقصة من نفس entity_id
  if(g.entity_id){
    for(const [ck,cg] of Object.entries(sd.messageCache)){
      if(ck===k) continue;
      if(cg.entity_id===g.entity_id){
        if(!g.pipeline_id && cg.pipeline_id){ g.pipeline_id=cg.pipeline_id; g.pipeline_name=cg.pipeline_name; }
        if(!g.stage_id && cg.stage_id){ g.stage_id=cg.stage_id; g.stage_name=cg.stage_name; }
        if(!g.message_texts?.length && cg.message_texts?.length) g.message_texts=cg.message_texts;
      }
    }
  }

  const finalText = pickFinalText(g.message_texts);
  const tags = Array.from(g.tags||[]);
  const intervention = determineInterventionType(g.pipeline_id, g.stage_id, tags);

  let action_required='log_only', should_respond=false;
  if(g.has_message && finalText){ action_required='process_message'; should_respond=true; }
  else if(g.is_new_lead && finalText){ action_required='process_new_lead_message'; should_respond=true; }
  else if(g.is_new_lead){ action_required='welcome_new_lead'; should_respond=true; }
  else if(g.stage_changed){ action_required='stage_transition'; should_respond=intervention.use_ai_agent; }
  else if(!finalText && !g.is_new_lead){ action_required='ignore'; should_respond=false; }

  const completeness_percentage = Math.min(100, Math.round((g.pulses_received / g.expected_pulses) * 100));
  let confidence_level='low';
  if(completeness_percentage>=90 && finalText) confidence_level='high';
  else if(completeness_percentage>=70 || finalText) confidence_level='medium';

  const out = {
    group_key: k,
    lead_id: g.lead_id || g.entity_id || '',
    chat_id: g.conversation_id || '',
    message_text: finalText || '',
    client_name: g.client_name || '',
    event_types: Array.from(g.unique_events||[]).join(', '),
    events_count: g.pulses_received,
    action_required, should_respond,
    event_time_utc: new Date(Number(g.created_at)*1000).toISOString(),
    received_at_utc: new Date().toISOString(),
    unique_keys: [g.message_id||'', g.talk_id||'', g.lead_id||'', g.entity_id||''].filter(Boolean).join('_'),
    pipeline_id: g.pipeline_id || '', pipeline_name: g.pipeline_name || 'Unknown Pipeline',
    pipeline_service: PIPELINE_CONFIG[g.pipeline_id]?.service || 'general',
    stage_id: g.stage_id || '', stage_name: g.stage_name || 'Initial',
    previous_stage_id: g.previous_stage_id || '', stage_changed: g.stage_changed,
    message_fingerprint: k, message_id: g.message_id || '', talk_id: g.talk_id || '', entity_id: g.entity_id || '',
    pipeline: { id:g.pipeline_id||'', name:g.pipeline_name||'Unknown Pipeline', service: PIPELINE_CONFIG[g.pipeline_id]?.service || 'general' },
    stage: { id:g.stage_id||'', name:g.stage_name||'Initial', previous_id:g.previous_stage_id||'', changed:g.stage_changed },
    tags, has_tags: tags.length>0,
    intervention: { type: intervention.type, use_ai_agent: intervention.use_ai_agent, requires_human: intervention.requires_human, priority: intervention.priority, reason: intervention.reason.join('; '), language: intervention.language, confidence: intervention.confidence },
    has_message: g.has_message, is_new_lead: g.is_new_lead,
    confidence_level, pulses_received: g.pulses_received, expected_pulses: g.expected_pulses, completeness_percentage,
    completeness_status: g.is_complete? 'complete':'partial', is_complete: g.is_complete,
    source: g.source || 'waba', platform: g.platform,
    service_type: intervention.service,
    response_channel: g.platform==='whatsapp'?'whatsapp': (g.platform==='instagram'?'instagram': (g.platform==='facebook'?'messenger':'unknown')),
    aggregation_time_ms: g.last_pulse_time - g.first_pulse_time,
    processing_time_ms: Date.now() - g.first_pulse_time,
    is_primary_record: true, processed: true, ready_for_processing: true, deduplication_count: g.pulses_received,
    cache_size: Object.keys(sd.messageCache).length, has_valid_content: !!finalText || g.is_new_lead
  };

  // علامة “تم معالجته” + تنظيف من الكاش لو مكتمل
  const processed = $getWorkflowStaticData('global').processedGroups; processed[k]=Date.now();
  if(g.is_complete) delete sd.messageCache[k];

  return { json: out };
});

const CONFIG = { MESSAGE_CACHE_TTL:120000 };
const sd = $getWorkflowStaticData('global');
if(!sd.messageCache) return [{ json:{ status:'no_cache' } }];
const before = Object.keys(sd.messageCache).length;
const now = Date.now();
for(const k in sd.messageCache) if(now - sd.messageCache[k].timestamp > CONFIG.MESSAGE_CACHE_TTL) delete sd.messageCache[k];
for(const k in sd.processedGroups || {}) if(now - sd.processedGroups[k] > CONFIG.MESSAGE_CACHE_TTL) delete sd.processedGroups[k];
const after = Object.keys(sd.messageCache).length;
return [{ json:{ status:'ok', removed: before-after, remaining: after } }];

