const headers = inputData?.json?.headers || {};

// دالة بسيطة جداً للاستخراج
function getValue(obj, key) {
  const val = obj[key];
  if (val === undefined || val === null) return "";
  if (typeof val === 'object') return JSON.stringify(val);
  return String(val);
}

