// ==========================================
// NODE: Queue Manager - منظم التدفق
// ==========================================
// ضع هذا الـ Node بين Extract Basic Info و Save to Google Sheets
// الهدف: تنظيم وتهدئة تدفق البيانات لتجنب التصادم

// الحصول على الذاكرة المؤقتة المشتركة
const staticData = $getWorkflowStaticData('global');

// تهيئة القائمة إذا لم تكن موجودة
if (!staticData.queue) {
  staticData.queue = [];
  staticData.lastProcessTime = 0;
  staticData.isProcessing = false;
  staticData.queueId = 0;
}

// إعدادات التحكم
const CONFIG = {
  MIN_DELAY_MS: 2000,        // أقل تأخير بين الكتابات (2 ثانية)
  MAX_QUEUE_SIZE: 10,        // أقصى حجم للقائمة قبل الإجبار على المعالجة
  MAX_WAIT_TIME: 5000,       // أقصى وقت انتظار (5 ثواني)
  BATCH_SIZE: 1,             // عدد السجلات في كل دفعة
  DEBUG: true
};

// دالة للطباعة
function log(...args) {
  if (CONFIG.DEBUG) {
    console.log(`[Queue Manager ${new Date().toISOString()}]`, ...args);
  }
}

// دالة للانتظار
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// استلام البيانات الواردة
const incomingData = $json;
const currentTime = Date.now();

// إضافة معرف فريد للسجل
incomingData.queue_id = ++staticData.queueId;
incomingData.queued_at = new Date().toISOString();

log(`Incoming record #${incomingData.queue_id}:`, {
  event_type: incomingData.event_type,
  lead_id: incomingData.lead_id,
  message: incomingData.message_text ? incomingData.message_text.substring(0, 30) : "EMPTY"
});

// إضافة للقائمة
staticData.queue.push(incomingData);
log(`Queue size: ${staticData.queue.length}`);

// حساب الوقت منذ آخر معالجة
const timeSinceLastProcess = currentTime - staticData.lastProcessTime;
log(`Time since last process: ${timeSinceLastProcess}ms`);

// تحديد هل نحتاج للمعالجة الآن
let shouldProcess = false;
let processReason = "";

// شروط المعالجة
if (staticData.queue.length >= CONFIG.MAX_QUEUE_SIZE) {
  shouldProcess = true;
  processReason = "Queue full";
} else if (timeSinceLastProcess >= CONFIG.MAX_WAIT_TIME && staticData.queue.length > 0) {
  shouldProcess = true;
  processReason = "Max wait time reached";
} else if (timeSinceLastProcess >= CONFIG.MIN_DELAY_MS && !staticData.isProcessing) {
  shouldProcess = true;
  processReason = "Min delay passed";
}

// إذا قررنا المعالجة
if (shouldProcess) {
  log(`Processing triggered: ${processReason}`);

  // منع المعالجة المتزامنة
  if (staticData.isProcessing) {
    log("Another process is running, waiting...");

    // انتظر حتى انتهاء المعالجة السابقة
    let waitCount = 0;
    while (staticData.isProcessing && waitCount < 50) {
      await sleep(100);
      waitCount++;
    }

    if (waitCount >= 50) {
      log("WARNING: Timeout waiting for previous process");
      staticData.isProcessing = false; // إعادة تعيين في حالة التعليق
    }
  }

  // بدء المعالجة
  staticData.isProcessing = true;

  try {
    // أخذ العدد المطلوب من القائمة
    const toProcess = staticData.queue.splice(0, CONFIG.BATCH_SIZE);

    if (toProcess.length > 0) {
      log(`Processing ${toProcess.length} record(s)`);

      // تحديث وقت آخر معالجة
      staticData.lastProcessTime = Date.now();

      // إضافة معلومات المعالجة
      const processedRecords = toProcess.map(record => {
        record.processed_from_queue = true;
        record.queue_wait_time = Date.now() - new Date(record.queued_at).getTime();
        record.queue_process_batch = staticData.queueId;

        // تنظيف القيم الفارغة
        Object.keys(record).forEach(key => {
          if (record[key] === undefined || record[key] === null) {
            record[key] = "";
          }
        });

        return { json: record };
      });

      log(`Sending to Google Sheets:`, {
        count: processedRecords.length,
        remaining_in_queue: staticData.queue.length
      });

      // إضافة تأخير صغير للأمان
      await sleep(500);

      // إنهاء المعالجة
      staticData.isProcessing = false;

      // إرجاع البيانات للكتابة
      return processedRecords;

    } else {
      log("No records to process");
      staticData.isProcessing = false;
      return [];
    }

  } catch (error) {
    log("ERROR during processing:", error.message);
    staticData.isProcessing = false;

    // في حالة الخطأ، أعد السجل للقائمة
    staticData.queue.unshift(incomingData);

    throw error;
  }

} else {
  // لا نعالج الآن، ننتظر
  log(`Queued for later processing. Waiting for: ${CONFIG.MIN_DELAY_MS - timeSinceLastProcess}ms`);

  // إذا كانت القائمة فارغة تقريباً وليس هناك معالجة، انتظر قليلاً ثم عالج
  if (staticData.queue.length === 1 && !staticData.isProcessing) {
    const waitTime = Math.max(0, CONFIG.MIN_DELAY_MS - timeSinceLastProcess);
    log(`Single record in queue, waiting ${waitTime}ms before processing`);

    await sleep(waitTime);

    // معالجة بعد الانتظار
    staticData.isProcessing = true;

    try {
      const toProcess = staticData.queue.splice(0, 1);
      staticData.lastProcessTime = Date.now();

      const record = toProcess[0];
      record.processed_from_queue = true;
      record.queue_wait_time = Date.now() - new Date(record.queued_at).getTime();

      // تنظيف القيم
      Object.keys(record).forEach(key => {
        if (record[key] === undefined || record[key] === null) {
          record[key] = "";
        }
      });

      log("Processing single record after wait");
      staticData.isProcessing = false;

      return [{ json: record }];

    } catch (error) {
      log("ERROR:", error.message);
      staticData.isProcessing = false;
      throw error;
    }
  }

  // لا شيء للإرجاع الآن
  return [];
}

