// بدلاً من crypto.createHash
const rawStr = (() => { 
  try { return JSON.stringify(input); } 
  catch { return String(input); }
})();

// hash بسيط لكن فعال
const simpleHash = (str) => {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  return `hash_${Math.abs(hash)}_${now.getTime()}`;
};

const contentHash = simpleHash(rawStr);

/**
 * This node flattens whatever comes in to multiple items for Google Sheets.
 * Use with Mode: "Run Once for All Items"
 */

const items = $input.all();
const out = [];

// حالة شائعة: عنصر واحد وداخله Array من الصفوف
if (items.length === 1 && Array.isArray(items[0].json)) {
  for (const x of items[0].json) out.push({ json: x });
  return out;
}

// fallback: لو العنصر الواحد يحتوي حقل items[]
if (items.length === 1 && Array.isArray(items[0].json?.items)) {
  for (const x of items[0].json.items) out.push({ json: x });
  return out;
}

// لو الداتا أصلًا جاية كعناصر جاهزة، مررها كما هي
if (items.length > 0 && !Array.isArray(items[0].json)) {
  return items;
}

// آخر حل: ولا حاجة تنطبق → رجّع العنصر نفسه لو موجود
return items;
